sql:
SELECT COUNT(DISTINCT report_name) AS unique_region_reports
FROM reports
WHERE report_type = 'Region' AND strftime('%Y', timestamp) = '2022';

SELECT aid_distribution_id, country_id, aid_type_id, amount
FROM aid_distribution
WHERE year = 2002 AND amount > 150;

SELECT c.country_name, ad.amount
FROM countries c
INNER JOIN aid_distribution ad ON c.country_id = ad.country_id
WHERE ad.amount = (
    SELECT MAX(amount) FROM aid_distribution
);

SELECT SUM(amount) 
FROM aid_distribution 
WHERE year = 2002;

SELECT *
FROM user_activity
WHERE user_id IN (
    SELECT user_id
    FROM users
    WHERE role = 'admin'
) AND timestamp > (
    SELECT MAX(timestamp)
    FROM reports
);

